function isPlainObject(x) {
  return x !== null && typeof x === 'object' && !Array.isArray(x);
}

function encode(s) {
  return encodeURIComponent(s);
}

function toValueString(v) {
  if (v === null) return '';
  return String(v);
}

export default function stringifyQueryString(params) {
  if (!isPlainObject(params)) {
    throw new TypeError('stringifyQueryString: params must be a plain object');
  }

  const keys = Object.keys(params).sort();
  const pairs = [];

  for (const key of keys) {
    const value = params[key];
    if (value === undefined) continue;

    const k = encode(String(key));

    if (Array.isArray(value)) {
      for (const item of value) {
        // item: string|number|boolean (per spec)
        const v = encode(toValueString(item));
        pairs.push(`${k}=${v}`);
      }
      continue;
    }

    const v = encode(toValueString(value));
    pairs.push(`${k}=${v}`);
  }

  return pairs.join('&');
}
